+        _mlContext = new MLContext(seed: 42);
+        _logger = logger;
+        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
+        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
+    }
+
+    public void TrainAndSave()
+    {
+        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
+            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
+
+        // With small dataset, use all data for training and evaluate on training set
+        // In production, use TrainTestSplit with more data
+        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);
+
+        var pipeline = _mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject))
+            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
+            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
+            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
+            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
+            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
+
+        _logger.LogInformation("Training model...");
+        var model = pipeline.Fit(split.TrainSet);
+
+        // Evaluate
+        var predictions = model.Transform(split.TestSet);
+        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);
+
+        _logger.LogInformation("=== Model Evaluation Metrics ===");
+        _logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
+        _logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
+        _logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
+        _logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);
+
+        _mlContext.Model.Save(model, data.Schema, _modelPath);
+        _logger.LogInformation("Model saved to {Path}", _modelPath);
+    }
+
+    public string ModelPath => _modelPath;
+}
